def detect_rag_oscillation(
    history: list[tuple[date, RAGStatus]],
    window: int = 6,
) -> bool:
    """
    Return True if the programme has flip-flopped between GREEN and non-GREEN
    more than twice in the last 'window' weeks.
    """
    recent = history[-window:] if len(history) >= window else history
    statuses = [s for _, s in recent]
    transitions = sum(
        1 for a, b in zip(statuses, statuses[1:])
        if (a == RAGStatus.GREEN) != (b == RAGStatus.GREEN)
    )
    return transitions > 2


def portfolio_green_audit(reports: list) -> list[dict]:
    """Flag GREEN-reported programmes with suspicious underlying metrics."""
    concerns = []
    for r in reports:
        if r.overall_rag != RAGStatus.GREEN:
            continue
        overdue = [m for m in r.milestones if m.slip_days > 5]
        if overdue:
            concerns.append({
                "programme": r.programme,
                "issue": "GREEN despite overdue milestones",
                "details": [m.name for m in overdue],
            })
    return concerns

@dataclass
class GenAIRAGDimensions:
    model_quality: RAGStatus
    data_readiness: RAGStatus
    safety_compliance: RAGStatus

    def aggregate(self) -> RAGStatus:
        order = [RAGStatus.BLOCKED, RAGStatus.RED, RAGStatus.AMBER, RAGStatus.GREEN]
        dims = [self.model_quality, self.data_readiness, self.safety_compliance]
        for worst in order:
            if worst in dims:
                return worst
        return RAGStatus.GREEN


@dataclass
class FullProgrammeRAG:
    delivery: RAGAssessment
    genai: GenAIRAGDimensions

    def overall(self) -> RAGStatus:
        order = [RAGStatus.BLOCKED, RAGStatus.RED, RAGStatus.AMBER, RAGStatus.GREEN]
        candidates = [self.delivery.status, self.genai.aggregate()]
        for worst in order:
            if worst in candidates:
                return worst
        return RAGStatus.GREEN

    def summary(self) -> str:
        o = self.overall()
        return (
            f"Overall: {o.value.upper()}  |  "
            f"Delivery: {self.delivery.status.value.upper()}  |  "
            f"Model: {self.genai.model_quality.value.upper()}  |  "
            f"Data: {self.genai.data_readiness.value.upper()}  |  "
            f"Safety: {self.genai.safety_compliance.value.upper()}"
        )
